#import <Foundation/Foundation.h>
#import "PLXPBleLocationDefined.h"
#import "PLXPBleLocationLifeManageProtocol.h"
#import "PLXPBleCarEventProtocol.h"

NS_ASSUME_NONNULL_BEGIN

@interface PLXPBleLocationManager : NSObject<PLXPBleLocationLifeManageProtocol,PLXPBleLocationDataUpdateProtocol,PLXPBleConnectEventProtocol,PLXPBleCarEventProtocol>

@property (nonatomic, assign) float parkingDistance;


+ (PLXPBleLocationManager *)sharedManager;

- (PLBLELocationResult)bleKeyIsInCar;


@end

NS_ASSUME_NONNULL_END

