164	#pragma mark — XPPollingLifeManageProtocol
165	- (void)initBlePollingWithKeySettingData:(PLXPKeySettingData *)keySettingData isRemedy:(BOOL)isRemedy {
166	    //更新设置以及白名单
167	    self.pollingRunMode = keySettingData.pollingRunMode;
168	    self.isRemedy = isRemedy;
169	    self.isPollingLockSoundOn = keySettingData.lockSoundOn;
170	    if ([PLVehicleConfigTool isBleLocationVersionV1]) {
171	
172	        PLXPPollingFirstPollingHandler *pollingHandler = [[PLXPPollingFirstPollingHandler alloc]init];
173	        pollingHandler.isConvenient = keySettingData.bleAutoSensitivity;
174	        self.pollingHandler = pollingHandler;
175	    } else if ([PLVehicleConfigTool isBleLocationVersionV2]) {
176	        PLXPPollingSecondOptHandler *pollingHandler = [[PLXPPollingSecondOptHandler alloc] init];
177	        // 是否要求从蓝牙也必须满足解锁条件才能解锁，E38由于已发布不使用该方案
178	        pollingHandler.unlockDistance = keySettingData.unlockDistance;
179	        pollingHandler.lockDistance = keySettingData.lockDistance;
180	        pollingHandler.enableUnlockDistance = keySettingData.enableUnlockDistance;
181	        pollingHandler.isWelcome = keySettingData.isWelcomeMode;
182	        pollingHandler.lockHoldOnSecond = keySettingData.lockHoldOnSecond;
183	        self.pollingHandler = pollingHandler;
184	    } else if ([PLVehicleConfigTool isBleLocationVersionV3]) {
185	        PLXPPollingKnnHandler *pollingHandler = [[PLXPPollingKnnHandler alloc]init];
186	        pollingHandler.unlockDistance = keySettingData.unlockDistance;
187	        pollingHandler.lockDistance = keySettingData.lockDistance;
188	        pollingHandler.enableUnlockDistance = keySettingData.enableUnlockDistance;
189	        pollingHandler.isWelcome = keySettingData.isWelcomeMode;
190	        pollingHandler.lockHoldOnSecond = keySettingData.lockHoldOnSecond;
191	        self.pollingHandler = pollingHandler;
192	    }
193	    self.pollingHandler.delegate = self;
194	    
195	//    [[PLXPBLEKeepAliveBussiness sharedInstance] onCarInfoReady]; // TODO: 检测拉活条件
196	    DLogTagInfo(kMultiBleOptTag, @"<PA>开始Polling初始化, %@", PLXPCTMediatorTool.vehicleTypeName);
197	    
198	    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(receiveKeyMessageSuccessAction:) name:XPVehicleNotification.DigitalKeyReceiveKeyMessageSuccess object:nil];
199	    
200	    [self.pollingHandler initPolling];
201	}
