203	- (void)receiveKeyMessageSuccessAction:(NSNotification *)notification {
204	    if (!self.pollingHandler) {
205	        return;
206	    }
207	    if ([self.pollingHandler isKindOfClass:[PLXPPollingSecondPollingHandler class]]) {
208	        PLXPPollingSecondPollingHandler *pollingHandler = (PLXPPollingSecondPollingHandler *)self.pollingHandler;
209	        pollingHandler.pollingShield = NO;
210	    }
211	}
