253	#pragma mark — XPBleLocationResultSyncProtocol
254	- (void)syncBleLocationResult:(NSDictionary *)locationResult {
255	    if (locationResult[@"distanceLevel"] != nil) {
256	        PLBLEKeyDistanceLevel distanceLevel = (PLBLEKeyDistanceLevel)[locationResult[@"distanceLevel"] intValue];
257	        [self.pollingHandler handleLocationDistanceLevel:distanceLevel];
258	    }
259	    if (locationResult[@"distance"] != nil) {
260	        float distance = [locationResult[@"distance"] floatValue];
261	        [self.pollingHandler handleLocationDistance:distance];
262	    }
263	#ifdef XPPollingSDK_Test_Mode
264	    XPBLEConnectionState bleConnectState = [PLPolllingTestMockSetting bleConnectState];
265	#else
266	    XPBLEConnectionState bleConnectState = XPVehicleSDK.shared.vehicleManager.currentVehicle.bleConnectState;
267	#endif  //XPPollingSDK_Test_Mode
268	    if (bleConnectState != XPBLEConnectionStateAvailable) {
269	        DLogTagInfo(kMultiBleOptTag, @"%@ 蓝牙未鉴权成功，不进行Polling权限预测",@(bleConnectState));
270	        return;
271	    }
272	    self.pollingHandler.locationResult = locationResult;
273	    [self.pollingHandler handleLocationResult:locationResult];
274	}
