348	#pragma mark - Private
349	- (void)resetAllPollingCommandLimit:(PLXPPollingHandler *)pollingHandler {
350	    DLogTagInfo(kBLEKeyPollingTag, @"重置所有重连次数");
351	    self.pollingUnlockTryCount = 0;
352	    self.pressUnlockTryCount = 0;
353	    self.pressUnlockTrunkCount = 0;
354	    self.pollingLockTryCount = 0;
355	    self.pollingUnlockEnableTryCount = 0;
356	    self.pollingUnlockDisableTryCount = 0;
357	    self.pollingUnlockTrunkEnableTryCount = 0;
358	    self.pollingUnlockTrunkDisableTryCount = 0;
359	}
360	
361	#pragma mark — sendPollingCommand
362	- (void)revealHttpLock {
363	    if(self.pollingRunMode != PLPollingRunModeLockAndUnlock && self.pollingRunMode != PLPollingRunModeLock){
364	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>不是Polling解闭锁,或不是Polling闭锁，不发4G闭锁");
365	        return;
366	    }
367	    if (self.beforeDisconnectTemporaryLockState == XPVehicleTempLockStateActive) {
368	        DLogTagInfo(kBLEKeyPollingTag, @"临停状态，不发4G闭锁");
369	        return;
370	    }
371	    
372	    if(self.beforeDisconnectDoorLockState == XPVehicleDoorLockStateLocked){
373	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>车门已锁，不发4G闭锁");
374	        return;
375	    }
376	    if(self.beforeDisconnectDriverSeatOccupied == XPDriverSeatStateOccupied){
377	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>主驾有人，不发4G闭锁");
378	        return;
379	    }
380	    
381	    PLBLEKeyDistanceLevel compareDistanceLevel = PLBLEKeyDistanceLevelEnableCircle;
382	    if (![PLVehicleConfigTool isBleLocationVersionV1]) {
383	        compareDistanceLevel = PLBLEKeyDistanceLevelUnlockCircle;
384	    }
385	    if(self.pollingHandler.distanceLevel <= compareDistanceLevel){
386	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>未超过解锁圈，不发4G闭锁");
387	        return;
388	    }
389	    if (![self.pollingHandler isCanRevealHttpLock]) {
390	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>未超过解锁圈，不发4G闭锁");
391	        return;
392	    }
393	    if(self.isPaused){
394	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>Polling暂停中，不发4G闭锁");
395	        return;
396	    }
397	    DLogTagInfo(kBLEKeyPollingTag, @"<PA>车门未锁，主蓝牙断开连接，不在解锁圈，且主驾无人，4G闭锁");
398	    [self sendPollingBussinessCommand:XPPollingBussiness4GRevertLock];
399	}
400	
401	- (void)lockIfNeedHttps{
402	    DLogTagInfo(kBLEKeyPollingTag, @"发送HTTPS上锁指令");
403	    self.httpsLockCommandStartTime =  [self.class timestamp];
404	    @weakify(self);
405	    [PLXPCommandTool sendCommand:XPVehicleCommandPollingLock success:^{
406	        DLogTagError(kBLEKeyPollingTag, @"<PA>发送HTTPS上锁指令成功");
407	#ifndef XPPollingSDK_Test_Mode
408	        [((id<XPVehiclePresenterEx>)XPVehicleSDK.shared.vehicleManager.currentVehicle).pollingDelegateCaller postAutoLockNotificationWithLockSuccess:YES];
409	#endif  //XPPollingSDK_Test_Mode
410	        @strongify(self);
411	#ifdef XPPollingSDK_Test_Mode
412	        XPBLEConnectionState bleConnectState = [PLPolllingTestMockSetting bleConnectState];
413	#else
414	        XPBLEConnectionState bleConnectState = XPVehicleSDK.shared.vehicleManager.currentVehicle.bleConnectState;
415	#endif  //XPPollingSDK_Test_Mode
416	        if (bleConnectState != XPBLEConnectionStateAvailable) {
417	            self.beforeDisconnectDoorLockState = XPVehicleDoorLockStateLocked;
418	        }
419	        if (self.isPollingLockSoundOn) {
420	            AudioServicesPlaySystemSoundWithCompletion(self.lockSoundID, ^{
421	                DLogTagInfo(kMultiBleOptTag, @"<PA>发送闭锁指令成功，声音");
422	            });
423	        }
424	        AudioServicesPlaySystemSoundWithCompletion(kSystemSoundID_Vibrate, ^{
425	            DLogTagInfo(kMultiBleOptTag, @"<PA>发送闭锁指令成功，震动");
426	        });
427	        [PLProxyManager.sharedManager.pollingProxy pollingLockResultWithIsSuccess:YES];
428	        [self handleStatisticHttpsLockCommandWithSuccess:YES errorCode:PLERRORCODE_default detailErrorCode:0];
429	        [self.pollingHandler pollingLockCommandDidSuccess];
430	    } failed:^(XPVehicleError * error) {
431	        DLogTagError(kBLEKeyPollingTag, @"<PA>发送HTTPS上锁指令失败");
432	        [PLProxyManager.sharedManager.pollingProxy pollingLockResultWithIsSuccess:NO];
433	#ifndef XPPollingSDK_Test_Mode
434	        [((id<XPVehiclePresenterEx>)XPVehicleSDK.shared.vehicleManager.currentVehicle).pollingDelegateCaller postAutoLockNotificationWithLockSuccess:NO];
435	#endif  //XPPollingSDK_Test_Mode
436	        [self handleStatisticHttpsLockCommandWithSuccess:NO errorCode:PLERRORCODE_sendifaFail detailErrorCode:0];
437	    }];
438	}
439	
440	- (void)sendPollingBussinessCommand:(XPPollingBussinessType)type {
441	    if (self.isPaused) {
442	        DLogTagInfo(kMultiBleOptTag, @"polling服务处于暂停状态，不执行任何polling指令");
443	        return;
444	    }
445	    
446	    switch (type) {
447	        case XPPollingBussinessPollingUnlock:
448	        {
449	            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送Polling解锁指令");
450	            self.prevUnlockCommandTime = [NSDate date];
451	            self.pollingUnlockTryCount += 1;
452	            [self sendUnlockCommand];
453	        }
454	            break;
455	        case XPPollingBussinessPollingLock:
456	        {
457	            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送Polling上锁指令");
458	            self.prevLockCommandTime = [NSDate date];
459	            self.pollingLockTryCount += 1;
460	            [self sendLockCommand];
461	        }
462	            break;
463	        case XPPollingBussinessPollingEnableDoorUnlock:
464	        {
465	            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送Polling可解锁指令");
466	            self.prevEnableCommandTime = [NSDate date];
467	            self.pollingUnlockEnableTryCount += 1;
468	            [self sendPollingUnlockEnableCommand];
469	        }
470	            break;
471	        case XPPollingBussinessPollingDisableDoorUnlock:
472	        {
473	            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送Polling不可解锁指令");
474	            self.prevDisableCommandTime = [NSDate date];
475	            self.pollingUnlockDisableTryCount += 1;
476	            [self sendPollingUnlockDisableCommand];
477	        }
478	            break;
479	        
480	        case XPPollingBussinessPollingEnableTrunkUnlock:
481	        {
482	            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送Polling可以打开后备箱指令");
483	            self.prevTrunkEnableCommandTime = [NSDate date];
484	            self.pollingUnlockTrunkEnableTryCount += 1;
485	            [self sendTrunckNeedOpenCommand];
486	        }
487	            break;
488	        case XPPollingBussinessPollingDisableTrunkUnlock:
489	        {
490	            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送Polling不可以打开后备箱指令");
491	            self.prevTrunkDisableCommandTime = [NSDate date];
492	            self.pollingUnlockTrunkDisableTryCount += 1;
493	            [self sendTrunckNeedNotOpenCommand];
494	        }
495	            break;
496	        case XPPollingBussinessPollingEnableChargePortUnlock:
497	            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送Polling可以打开充电口指令");
498	            [self sendChargPortEnableCommand];
499	            break;
500	        case XPPollingBussinessPollingDisableChargePortUnlock:
501	            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送Polling不可以打开充电口指令");
502	            [self sendChargPortDisableCommand];
503	            break;
504	        case XPPollingBussinessPressDoorUnlock:
505	            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送手动解锁车辆指令");
506	            self.prevHandUnlockCommnadTime = [NSDate date];
507	            self.pressUnlockTryCount += 1;
508	            [self sendHandUnlockCommand];
509	            break;
510	        case XPPollingBussinessPressTrunkUnlock:
511	            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送解锁后尾箱指令");
512	            self.prevHandTrunkUnlockCommandTime = [NSDate date];
513	            self.pressUnlockTrunkCount += 1;
514	            [self sendTrunkOpenCommand];
515	            break;
516	        case XPPollingBussinessPressSlowChargePortUnlock:
517	        {
518	            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送解锁充电口指令");
519	            self.preHandSlowChargeOpenCommandTime = [NSDate date];
520	            [self sendSlowChargePortOpen];
521	        }
522	            break;
523	        case XPPollingBussinessPressFastChargePortUnlock:
524	        {
525	            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送解锁快充口指令");
526	            self.preHandFastChargeOpenCommandTime = [NSDate date];
527	            [self sendFastChargePortOpen];
528	        }
529	            break;
530	        case XPPollingBussinessEnablePollingLockRevert:
531	        {
532	            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送可闭锁兜底指令");
533	            [self sendIsEnableLockRevert];
534	        }
535	            break;
536	        case XPPollingBussinessDisablePollingLockRevert:
537	        {
538	            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送不可闭锁兜底指令");
539	            [self sendIsDisableLockRevert];
540	        }
541	            break;
542	        case XPPollingBussiness4GRevertLock:
543	            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送4G闭锁兜底指令");
544	            [self lockIfNeedHttps];
545	            break;
546	            
547	        default:
548	            break;
549	    }
