588	- (void)sendLockCommand {
589	    if(ALL_WORK_KEY_EXIST) {
590	        [self sendAllWorkCommand:PLXPTBoxCommandPollingLock];
591	    } else {
592	        self.httpsLockCommandStartTime = [self.class timestamp];
593	        if(!PLXPCTMediatorTool.isNetworkReachable){
594	            DLogTagInfo(kBLEKeyPollingTag, @"无网络，不发送双通道HTTPS上锁指令");
595	        }
596	        @weakify(self);
597	        [PLXPCommandTool sendCommand:XPVehicleCommandPollingLock success:^{
598	            @strongify(self);
599	            DLogTagError(kBLEKeyPollingTag, @"<PA>发送双通道HTTP上锁指令成功");
600	            if (self.pollingHandler) {
601	#ifdef XPPollingSDK_Test_Mode
602	                XPBLEConnectionState bleConnectState = [PLPolllingTestMockSetting bleConnectState];
603	#else
604	                XPBLEConnectionState bleConnectState = XPVehicleSDK.shared.vehicleManager.currentVehicle.bleConnectState;
605	#endif  //XPPollingSDK_Test_Mode
606	                if(bleConnectState != XPBLEConnectionStateAvailable){
607	                    self.beforeDisconnectDoorLockState = XPVehicleDoorLockStateLocked;
608	                }
609	#ifndef XPPollingSDK_Test_Mode
610	                [((id<XPVehiclePresenterEx>)XPVehicleSDK.shared.vehicleManager.currentVehicle).pollingDelegateCaller postAutoLockNotificationWithLockSuccess:YES];
611	#endif  //XPPollingSDK_Test_Mode
612	
613	            }
614	            if(self.isPollingLockSoundOn){
615	                AudioServicesPlaySystemSoundWithCompletion(self.lockSoundID, ^{
616	                    DLogTagInfo(kMultiBleOptTag, @"<PA>发送闭锁指令成功，声音");
617	                });
618	            }
619	            AudioServicesPlaySystemSoundWithCompletion(kSystemSoundID_Vibrate, ^{
620	                DLogTagInfo(kMultiBleOptTag, @"<PA>发送闭锁指令成功，震动");
621	            });
622	            [PLProxyManager.sharedManager.pollingProxy pollingLockResultWithIsSuccess:YES];
623	            [self handleStatisticHttpsLockCommandWithSuccess:YES errorCode:PLERRORCODE_default detailErrorCode:0];
624	
625	        } failed:^(XPVehicleError * error) {
626	            if (error.channel == XPVehicleChannelTCP) {
627	                DLogTagError(kBLEKeyPollingTag, @"<PA>发送双通道HTTP上锁指令失败");
628	                if (self.pollingHandler) {
629	#ifndef XPPollingSDK_Test_Mode
630	                    [((id<XPVehiclePresenterEx>)XPVehicleSDK.shared.vehicleManager.currentVehicle).pollingDelegateCaller postAutoLockNotificationWithLockSuccess:NO];
631	#endif  //XPPollingSDK_Test_Mode
632	                }
633	                [self handleStatisticHttpsLockCommandWithSuccess:NO errorCode:PLERRORCODE_sendifaFail detailErrorCode:0];
634	            } else {
635	                DLogTagError(kBLEKeyPollingTag, @"<PA>发送双通道上锁指令失败");
636	            }
637	            [PLProxyManager.sharedManager.pollingProxy pollingLockResultWithIsSuccess:NO];
638	        }];
639	    }
640	}
