1285	    _pollingRunMode = pollingRunMode;
1286	    [self.pollingHandler evaluateAndUpdatePollingEvent];
1287	}
1288	
1289	- (void)setIsPaused:(BOOL)isPaused {
1290	    if (!_isPaused && isPaused) {
1291	        [self.pollingHandler forceDisableAllEnableCmd];
1292	    }
1293	    _isPaused = isPaused;
1294	    DLogTagInfo(kMultiBleOptTag, @"设置PollingSDK是否暂停:%d",isPaused);
1295	}
1296	
1297	- (void)setIsPollingLockSoundOn:(BOOL)isPollingLockSoundOn {
1298	    _isPollingLockSoundOn = isPollingLockSoundOn;
1299	    DLogTagInfo(kMultiBleOptTag, @"设置isPollingLockSoundOn:%d",isPollingLockSoundOn);
1300	}
