//
//  XPPollingManager.m
//  XiaoPengQiChe
//
//  Created by 孙晓波 on 2021/2/23.
//  Copyright © 2021 xiaopeng.com. All rights reserved.
//

#import "PLXPPollingManager.h"
#import "PLXPPollingFirstPollingHandler.h"
#import "PLXPPollingSecondPollingHandler.h"
#import "PLXPPollingSecondOptHandler.h"
#import <AudioToolbox/AudioToolbox.h>
#import "PLXPEvent.h"
#import "PLXPPollingKnnHandler.h"
#import "PLProxyManager.h"
#import "PLXPCommandTool.h"
#import "PLVehicleConfigTool.h"
#import "PLVehicleStateInstance.h"
#ifdef XPPollingSDK_Test_Mode
#import "PLPolllingTestMockSetting.h"
#else
@import XPVehicleSDK;
#endif  //XPPollingSDK_Test_Mode

typedef NS_ENUM(NSInteger, PLXPError_Code) {
    PLERRORCODE_default         = 0, // 默认值
    PLERRORCODE_tokenFail       = 1, // 获取token失败
    PLERRORCODE_sendifaFail     = 2, // 发送报文失败
    PLERRORCODE_timeOut         = 3, // 超时
    PLERRORCODE_carFail         = 4, // 车端执行失败
    PLERRORCODE_faceFail        = 5, // 人脸认证失败
    PLERRORCODE_checkFail       = 6, // 没有查询结果失败
    PLERRORCODE_emptyIffa       = 7, // 本地没有报文
};

typedef NS_ENUM(NSUInteger, XPPollingBussinessType) {
    XPPollingBussinessNone                              = 0,
    XPPollingBussinessPollingUnlock                     = 1,
    XPPollingBussinessPollingLock                       = 2,
    XPPollingBussinessPollingEnableDoorUnlock           = 3,
    XPPollingBussinessPollingDisableDoorUnlock          = 4,
    XPPollingBussinessPollingEnableTrunkUnlock          = 5,
    XPPollingBussinessPollingDisableTrunkUnlock         = 6,
    XPPollingBussinessPollingEnableChargePortUnlock     = 7,
    XPPollingBussinessPollingDisableChargePortUnlock    = 8,
    XPPollingBussinessPressDoorUnlock                   = 9,
    XPPollingBussinessPressTrunkUnlock                  = 10,
    XPPollingBussinessPressSlowChargePortUnlock         = 11,
    XPPollingBussinessPressFastChargePortUnlock         = 12,
    XPPollingBussinessEnablePollingLockRevert           = 13,
    XPPollingBussinessDisablePollingLockRevert          = 14,
    XPPollingBussiness4GRevertLock                      = 15
};

@interface PLXPPollingManager()<PLXPPollingHandlerDelegate,
PLXPPollingSecondPollingHandlerDelegate,
PLVehicleStateInstanceProtocol>

@property (nonatomic, assign) PLPollingRunMode pollingRunMode;
@property (nonatomic, strong) PLXPPollingHandler *pollingHandler;

@property (nonatomic, assign) SystemSoundID lockSoundID;
@property (nonatomic,assign) BOOL isPollingLockSoundOn;

@property (nonatomic, assign) BOOL isDoorOpen;


@property (nonatomic, assign) BOOL isPaused;
@property (nonatomic, assign) BOOL isRemedy;

@property (nonatomic, strong) NSDate *prevLockCommandTime;
@property (nonatomic, strong) NSDate *prevUnlockCommandTime;
@property (nonatomic, strong) NSDate *prevEnableCommandTime;
@property (nonatomic, strong) NSDate *prevDisableCommandTime;
@property (nonatomic, strong) NSDate *prevHandUnlockCommnadTime;
@property (nonatomic, strong) NSDate *prevHandTrunkUnlockCommandTime;
@property (nonatomic, strong) NSDate *prevTrunkEnableCommandTime;
@property (nonatomic, strong) NSDate *prevTrunkDisableCommandTime;
@property (nonatomic, strong) NSDate *preHandSlowChargeOpenCommandTime;
@property (nonatomic, strong) NSDate *preHandFastChargeOpenCommandTime;

@property (nonatomic, assign) NSInteger pollingUnlockTryCount;
@property (nonatomic, assign) NSInteger pressUnlockTryCount;
@property (nonatomic, assign) NSInteger pressUnlockTrunkCount;
@property (nonatomic, assign) NSInteger pollingLockTryCount;
@property (nonatomic, assign) NSInteger pollingUnlockEnableTryCount;
@property (nonatomic, assign) NSInteger pollingUnlockDisableTryCount;
@property (nonatomic, assign) NSInteger pollingUnlockTrunkEnableTryCount;
@property (nonatomic, assign) NSInteger pollingUnlockTrunkDisableTryCount;

//用于双通道闭锁
@property (nonatomic, assign) NSTimeInterval httpsLockCommandStartTime;

@property (nonatomic, assign) XPVehicleDoorLockState beforeDisconnectDoorLockState;
@property (nonatomic, assign) XPDriverSeatState beforeDisconnectDriverSeatOccupied;
@property (nonatomic, assign) XPVehicleTempLockState beforeDisconnectTemporaryLockState;

@end

@implementation PLXPPollingManager

+ (PLXPPollingManager *)sharedManager {
    static id sharedMyModel = nil;
#if !defined(MONA_APP)
    static dispatch_once_t onceToken;

    dispatch_once(&onceToken, ^{
        sharedMyModel = [[self alloc] init];
    });
#endif
    return sharedMyModel;
}

- (id)init {
    self = [super init];
    if(self) {
        _beforeDisconnectDoorLockState = XPVehicleDoorLockStateDefault;
        _beforeDisconnectDriverSeatOccupied = XPDriverSeatStateDefault;
        _beforeDisconnectTemporaryLockState = XPVehicleTempLockStateDefault;
        NSString *pathUrl = [[NSBundle mainBundle] pathForResource:@"XPPollingSDK" ofType:@"bundle"];
        NSString *lockSoundFilePath = [[NSBundle bundleWithPath:pathUrl] pathForResource:@"lockPollingSDK" ofType:@"mp3"];
        if (lockSoundFilePath && ![lockSoundFilePath isEqualToString:@""]) {
            AudioServicesCreateSystemSoundID((__bridge CFURLRef _Nonnull)[NSURL fileURLWithPath:lockSoundFilePath], &_lockSoundID);
        }

    }
    return self;
}

- (void)start {
    @weakify(self)
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        @strongify(self)
        self.beforeDisconnectDoorLockState = XPVehicleDoorLockStateDefault;
        self.beforeDisconnectDriverSeatOccupied = XPDriverSeatStateDefault;
        self.beforeDisconnectTemporaryLockState = XPVehicleTempLockStateDefault;
        [[PLVehicleStateInstance shareInstance] addListener:self];
    });
}

- (void)vehicleStateChanged:(XPVehicleStateNotiObject *)object {
    XPVehicleDoorLockState doorState = (XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]);
    if (doorState != XPVehicleDoorLockStateDefault) {
        self.beforeDisconnectDoorLockState = doorState;
    }

    XPDriverSeatState seatState = (XPDriverSeatState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"seat"][@"driver_seat_state"]);
    if (seatState != XPDriverSeatStateDefault) {
        self.beforeDisconnectDriverSeatOccupied = seatState;
    }

    XPVehicleTempLockState temp_lock_st = (XPVehicleTempLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"temp_lock_st"]);
    if (temp_lock_st != XPVehicleTempLockStateDefault) {
        self.beforeDisconnectTemporaryLockState = temp_lock_st;
    }
}

- (void)dealloc{
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

#pragma mark — XPPollingLifeManageProtocol
- (void)initBlePollingWithKeySettingData:(PLXPKeySettingData *)keySettingData isRemedy:(BOOL)isRemedy {
    //更新设置以及白名单
    self.pollingRunMode = keySettingData.pollingRunMode;
    self.isRemedy = isRemedy;
    self.isPollingLockSoundOn = keySettingData.lockSoundOn;
    if ([PLVehicleConfigTool isBleLocationVersionV1]) {

        PLXPPollingFirstPollingHandler *pollingHandler = [[PLXPPollingFirstPollingHandler alloc]init];
        pollingHandler.isConvenient = keySettingData.bleAutoSensitivity;
        self.pollingHandler = pollingHandler;
    } else if ([PLVehicleConfigTool isBleLocationVersionV2]) {
        PLXPPollingSecondOptHandler *pollingHandler = [[PLXPPollingSecondOptHandler alloc] init];
        // 是否要求从蓝牙也必须满足解锁条件才能解锁，E38由于已发布不使用该方案
        pollingHandler.unlockDistance = keySettingData.unlockDistance;
        pollingHandler.lockDistance = keySettingData.lockDistance;
        pollingHandler.enableUnlockDistance = keySettingData.enableUnlockDistance;
        pollingHandler.isWelcome = keySettingData.isWelcomeMode;
        pollingHandler.lockHoldOnSecond = keySettingData.lockHoldOnSecond;
        self.pollingHandler = pollingHandler;
    } else if ([PLVehicleConfigTool isBleLocationVersionV3]) {
        PLXPPollingKnnHandler *pollingHandler = [[PLXPPollingKnnHandler alloc]init];
        pollingHandler.unlockDistance = keySettingData.unlockDistance;
        pollingHandler.lockDistance = keySettingData.lockDistance;
        pollingHandler.enableUnlockDistance = keySettingData.enableUnlockDistance;
        pollingHandler.isWelcome = keySettingData.isWelcomeMode;
        pollingHandler.lockHoldOnSecond = keySettingData.lockHoldOnSecond;
        self.pollingHandler = pollingHandler;
    }
    self.pollingHandler.delegate = self;

//    [[PLXPBLEKeepAliveBussiness sharedInstance] onCarInfoReady]; // TODO: 检测拉活条件
    DLogTagInfo(kMultiBleOptTag, @"<PA>开始Polling初始化, %@", PLXPCTMediatorTool.vehicleTypeName);

    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(receiveKeyMessageSuccessAction:) name:XPVehicleNotification.DigitalKeyReceiveKeyMessageSuccess object:nil];

    [self.pollingHandler initPolling];
}

- (void)receiveKeyMessageSuccessAction:(NSNotification *)notification {
    if (!self.pollingHandler) {
        return;
    }
    if ([self.pollingHandler isKindOfClass:[PLXPPollingSecondPollingHandler class]]) {
        PLXPPollingSecondPollingHandler *pollingHandler = (PLXPPollingSecondPollingHandler *)self.pollingHandler;
        pollingHandler.pollingShield = NO;
    }
}

- (void)deinitBlePolling {
    DLogTagInfo(kMultiBleOptTag, @"释放polling资源");
    [self pauseBlePolling];
    [self.pollingHandler deinitPolling];
    self.pollingHandler = nil;
    [self resetAllPollingCommandLimit:nil];
    [[NSNotificationCenter defaultCenter] removeObserver:self name:XPVehicleNotification.DigitalKeyReceiveKeyMessageSuccess object:nil];
}

- (void)pauseBlePolling {
    self.isPaused = YES;
}

- (void)remuseBlePolling {
    self.isPaused = NO;
}

#pragma mark — XPBlePollingDataUpdateProtocol
- (void)updatePollingKeyData:(PLXPKeySettingData *)keySettingData {
    self.pollingRunMode = keySettingData.pollingRunMode;
    self.isPollingLockSoundOn = keySettingData.lockSoundOn;
    if ([self.pollingHandler isKindOfClass:[PLXPPollingSecondPollingHandler class]]) {
        PLXPPollingSecondPollingHandler *pollingHandler = (PLXPPollingSecondPollingHandler *)self.pollingHandler;
        [pollingHandler setPollingUnlockWithWelcome:keySettingData.isWelcomeMode];
        pollingHandler.unlockDistance = keySettingData.unlockDistance;
        pollingHandler.lockDistance = keySettingData.lockDistance;
        pollingHandler.enableUnlockDistance = keySettingData.enableUnlockDistance;
        pollingHandler.lockHoldOnSecond = keySettingData.lockHoldOnSecond;
    }
    if ([self.pollingHandler isKindOfClass:[PLXPPollingFirstPollingHandler class]]) {
        PLXPPollingFirstPollingHandler *handler = (PLXPPollingFirstPollingHandler *)self.pollingHandler;
        handler.isConvenient = keySettingData.bleAutoSensitivity;
    }
}

- (void)updateCarStateIsRemedy:(BOOL)isRemedy {
    self.isRemedy = isRemedy;
}


#pragma mark — XPBleLocationResultSyncProtocol
- (void)syncBleLocationResult:(NSDictionary *)locationResult {
    if (locationResult[@"distanceLevel"] != nil) {
        PLBLEKeyDistanceLevel distanceLevel = (PLBLEKeyDistanceLevel)[locationResult[@"distanceLevel"] intValue];
        [self.pollingHandler handleLocationDistanceLevel:distanceLevel];
    }
    if (locationResult[@"distance"] != nil) {
        float distance = [locationResult[@"distance"] floatValue];
        [self.pollingHandler handleLocationDistance:distance];
    }
#ifdef XPPollingSDK_Test_Mode
    XPBLEConnectionState bleConnectState = [PLPolllingTestMockSetting bleConnectState];
#else
    XPBLEConnectionState bleConnectState = XPVehicleSDK.shared.vehicleManager.currentVehicle.bleConnectState;
#endif  //XPPollingSDK_Test_Mode
    if (bleConnectState != XPBLEConnectionStateAvailable) {
        DLogTagInfo(kMultiBleOptTag, @"%@ 蓝牙未鉴权成功，不进行Polling权限预测",@(bleConnectState));
        return;
    }
    self.pollingHandler.locationResult = locationResult;
    [self.pollingHandler handleLocationResult:locationResult];
}

- (void)bleKeyIsFarAway {
    self.pollingHandler.isWatchLocked = NO;
}

#pragma mark — XPBleConnectEventProtocol
- (void)bleDefinedConnected {
    [self.pollingHandler detectBleConnect:NO];
}

- (void)bleDefinedDisconnect {
    [self.pollingHandler detectBleRetryDisconnect];
    [self resetAllPollingCommandLimit:nil];
    [self revealHttpLock];
}

- (void)bleRetryConnected {
    [self.pollingHandler detectBleConnect:YES];
}

- (void)bleSystemSwitch:(BOOL)isOn {
    if (isOn) {
        DLogTagInfo(kMultiBleOptTag, @"打开蓝牙设置，isFirstComming置为YES");
        if ([self.pollingHandler isKindOfClass:[PLXPPollingSecondPollingHandler class]]) {
            PLXPPollingSecondPollingHandler *pollingHandler = (PLXPPollingSecondPollingHandler *)self.pollingHandler;
            pollingHandler.isFirstComming = YES;
        }
    } else {
        DLogTagInfo(kMultiBleOptTag, @"<PA>蓝牙设置关闭，尝试发送4G闭锁");
        [self revealHttpLock];
    }
}

#pragma mark — XPBleCarEventProtocol
- (void)carLockIsUnlocked {
    [self resetAllPollingCommandLimit:nil];
    [self.pollingHandler detectCarIsUnlocked];
}

- (void)carLockIsLocked {
    [self resetAllPollingCommandLimit:nil];
    [self.pollingHandler detectCarIsLocked];
}

- (void)carDoorIsOpen {
    self.isDoorOpen = YES;
    [self.pollingHandler doorOpenResetLimit];
}

- (void)carDoorIsClose {
    self.isDoorOpen = NO;
}

- (void)carDoorHadOpened {
    if ([self.pollingHandler isKindOfClass:[PLXPPollingSecondPollingHandler class]]) {
        PLXPPollingSecondPollingHandler *pollingHandler = (PLXPPollingSecondPollingHandler *)self.pollingHandler;
        pollingHandler.hasOpenDoor = YES;
    }
    [self resetAllPollingCommandLimit:nil];
}

- (void)carIsLockedByWatch {
    self.pollingHandler.isWatchLocked = YES;
}

- (void)carIsUnlockedByWatch {
    self.pollingHandler.isWatchLocked = NO;
}

- (void)enterMyCarPage {
    self.pollingHandler.isWatchLocked = NO;
}

#pragma mark - Private
- (void)resetAllPollingCommandLimit:(PLXPPollingHandler *)pollingHandler {
    DLogTagInfo(kBLEKeyPollingTag, @"重置所有重连次数");
    self.pollingUnlockTryCount = 0;
    self.pressUnlockTryCount = 0;
    self.pressUnlockTrunkCount = 0;
    self.pollingLockTryCount = 0;
    self.pollingUnlockEnableTryCount = 0;
    self.pollingUnlockDisableTryCount = 0;
    self.pollingUnlockTrunkEnableTryCount = 0;
    self.pollingUnlockTrunkDisableTryCount = 0;
}

#pragma mark — sendPollingCommand
- (void)revealHttpLock {
    if(self.pollingRunMode != PLPollingRunModeLockAndUnlock && self.pollingRunMode != PLPollingRunModeLock){
        DLogTagInfo(kBLEKeyPollingTag, @"<PA>不是Polling解闭锁,或不是Polling闭锁，不发4G闭锁");
        return;
    }
    if (self.beforeDisconnectTemporaryLockState == XPVehicleTempLockStateActive) {
        DLogTagInfo(kBLEKeyPollingTag, @"临停状态，不发4G闭锁");
        return;
    }

    if(self.beforeDisconnectDoorLockState == XPVehicleDoorLockStateLocked){
        DLogTagInfo(kBLEKeyPollingTag, @"<PA>车门已锁，不发4G闭锁");
        return;
    }
    if(self.beforeDisconnectDriverSeatOccupied == XPDriverSeatStateOccupied){
        DLogTagInfo(kBLEKeyPollingTag, @"<PA>主驾有人，不发4G闭锁");
        return;
    }

    PLBLEKeyDistanceLevel compareDistanceLevel = PLBLEKeyDistanceLevelEnableCircle;
    if (![PLVehicleConfigTool isBleLocationVersionV1]) {
        compareDistanceLevel = PLBLEKeyDistanceLevelUnlockCircle;
    }
    if(self.pollingHandler.distanceLevel <= compareDistanceLevel){
        DLogTagInfo(kBLEKeyPollingTag, @"<PA>未超过解锁圈，不发4G闭锁");
        return;
    }
    if (![self.pollingHandler isCanRevealHttpLock]) {
        DLogTagInfo(kBLEKeyPollingTag, @"<PA>未超过解锁圈，不发4G闭锁");
        return;
    }
    if(self.isPaused){
        DLogTagInfo(kBLEKeyPollingTag, @"<PA>Polling暂停中，不发4G闭锁");
        return;
    }
    DLogTagInfo(kBLEKeyPollingTag, @"<PA>车门未锁，主蓝牙断开连接，不在解锁圈，且主驾无人，4G闭锁");
    [self sendPollingBussinessCommand:XPPollingBussiness4GRevertLock];
}

- (void)lockIfNeedHttps{
    DLogTagInfo(kBLEKeyPollingTag, @"发送HTTPS上锁指令");
    self.httpsLockCommandStartTime =  [self.class timestamp];
    @weakify(self);
    [PLXPCommandTool sendCommand:XPVehicleCommandPollingLock success:^{
        DLogTagError(kBLEKeyPollingTag, @"<PA>发送HTTPS上锁指令成功");
#ifndef XPPollingSDK_Test_Mode
        [((id<XPVehiclePresenterEx>)XPVehicleSDK.shared.vehicleManager.currentVehicle).pollingDelegateCaller postAutoLockNotificationWithLockSuccess:YES];
#endif  //XPPollingSDK_Test_Mode
        @strongify(self);
#ifdef XPPollingSDK_Test_Mode
        XPBLEConnectionState bleConnectState = [PLPolllingTestMockSetting bleConnectState];
#else
        XPBLEConnectionState bleConnectState = XPVehicleSDK.shared.vehicleManager.currentVehicle.bleConnectState;
#endif  //XPPollingSDK_Test_Mode
        if (bleConnectState != XPBLEConnectionStateAvailable) {
            self.beforeDisconnectDoorLockState = XPVehicleDoorLockStateLocked;
        }
        if (self.isPollingLockSoundOn) {
            AudioServicesPlaySystemSoundWithCompletion(self.lockSoundID, ^{
                DLogTagInfo(kMultiBleOptTag, @"<PA>发送闭锁指令成功，声音");
            });
        }
        AudioServicesPlaySystemSoundWithCompletion(kSystemSoundID_Vibrate, ^{
            DLogTagInfo(kMultiBleOptTag, @"<PA>发送闭锁指令成功，震动");
        });
        [PLProxyManager.sharedManager.pollingProxy pollingLockResultWithIsSuccess:YES];
        [self handleStatisticHttpsLockCommandWithSuccess:YES errorCode:PLERRORCODE_default detailErrorCode:0];
        [self.pollingHandler pollingLockCommandDidSuccess];
    } failed:^(XPVehicleError * error) {
        DLogTagError(kBLEKeyPollingTag, @"<PA>发送HTTPS上锁指令失败");
        [PLProxyManager.sharedManager.pollingProxy pollingLockResultWithIsSuccess:NO];
#ifndef XPPollingSDK_Test_Mode
        [((id<XPVehiclePresenterEx>)XPVehicleSDK.shared.vehicleManager.currentVehicle).pollingDelegateCaller postAutoLockNotificationWithLockSuccess:NO];
#endif  //XPPollingSDK_Test_Mode
        [self handleStatisticHttpsLockCommandWithSuccess:NO errorCode:PLERRORCODE_sendifaFail detailErrorCode:0];
    }];
}

- (void)sendPollingBussinessCommand:(XPPollingBussinessType)type {
    if (self.isPaused) {
        DLogTagInfo(kMultiBleOptTag, @"polling服务处于暂停状态，不执行任何polling指令");
        return;
    }

    switch (type) {
        case XPPollingBussinessPollingUnlock:
        {
            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送Polling解锁指令");
            self.prevUnlockCommandTime = [NSDate date];
            self.pollingUnlockTryCount += 1;
            [self sendUnlockCommand];
        }
            break;
        case XPPollingBussinessPollingLock:
        {
            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送Polling上锁指令");
            self.prevLockCommandTime = [NSDate date];
            self.pollingLockTryCount += 1;
            [self sendLockCommand];
        }
            break;
        case XPPollingBussinessPollingEnableDoorUnlock:
        {
            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送Polling可解锁指令");
            self.prevEnableCommandTime = [NSDate date];
            self.pollingUnlockEnableTryCount += 1;
            [self sendPollingUnlockEnableCommand];
        }
            break;
        case XPPollingBussinessPollingDisableDoorUnlock:
        {
            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送Polling不可解锁指令");
            self.prevDisableCommandTime = [NSDate date];
            self.pollingUnlockDisableTryCount += 1;
            [self sendPollingUnlockDisableCommand];
        }
            break;

        case XPPollingBussinessPollingEnableTrunkUnlock:
        {
            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送Polling可以打开后备箱指令");
            self.prevTrunkEnableCommandTime = [NSDate date];
            self.pollingUnlockTrunkEnableTryCount += 1;
            [self sendTrunckNeedOpenCommand];
        }
            break;
        case XPPollingBussinessPollingDisableTrunkUnlock:
        {
            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送Polling不可以打开后备箱指令");
            self.prevTrunkDisableCommandTime = [NSDate date];
            self.pollingUnlockTrunkDisableTryCount += 1;
            [self sendTrunckNeedNotOpenCommand];
        }
            break;
        case XPPollingBussinessPollingEnableChargePortUnlock:
            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送Polling可以打开充电口指令");
            [self sendChargPortEnableCommand];
            break;
        case XPPollingBussinessPollingDisableChargePortUnlock:
            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送Polling不可以打开充电口指令");
            [self sendChargPortDisableCommand];
            break;
        case XPPollingBussinessPressDoorUnlock:
            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送手动解锁车辆指令");
            self.prevHandUnlockCommnadTime = [NSDate date];
            self.pressUnlockTryCount += 1;
            [self sendHandUnlockCommand];
            break;
        case XPPollingBussinessPressTrunkUnlock:
            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送解锁后尾箱指令");
            self.prevHandTrunkUnlockCommandTime = [NSDate date];
            self.pressUnlockTrunkCount += 1;
            [self sendTrunkOpenCommand];
            break;
        case XPPollingBussinessPressSlowChargePortUnlock:
        {
            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送解锁充电口指令");
            self.preHandSlowChargeOpenCommandTime = [NSDate date];
            [self sendSlowChargePortOpen];
        }
            break;
        case XPPollingBussinessPressFastChargePortUnlock:
        {
            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送解锁快充口指令");
            self.preHandFastChargeOpenCommandTime = [NSDate date];
            [self sendFastChargePortOpen];
        }
            break;
        case XPPollingBussinessEnablePollingLockRevert:
        {
            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送可闭锁兜底指令");
            [self sendIsEnableLockRevert];
        }
            break;
        case XPPollingBussinessDisablePollingLockRevert:
        {
            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送不可闭锁兜底指令");
            [self sendIsDisableLockRevert];
        }
            break;
        case XPPollingBussiness4GRevertLock:
            DLogTagInfo(kBLEKeyPollingTag, @"<PA>发送4G闭锁兜底指令");
            [self lockIfNeedHttps];
            break;

        default:
            break;
    }
}


- (void)sendUnlockCommand {
    if(ALL_WORK_KEY_EXIST) {
        [self sendAllWorkCommand:PLXPTBoxCommandPollingUnlock];
    } else {
        @weakify(self);
        [PLXPCommandTool sendCommand:XPVehicleCommandPollingUnlock success:^{ 
            @strongify(self);
            DLogTagInfo(kBLEKeyPollingTag, @"解锁成功，isFirstComming置为NO");
            if ([self.pollingHandler isKindOfClass:[PLXPPollingSecondPollingHandler class]]) {
                PLXPPollingSecondPollingHandler *pollingHandler = (PLXPPollingSecondPollingHandler *)self.pollingHandler;
                if (pollingHandler.isFirstComming) {
                    pollingHandler.observeDoorOpen = YES;
                }
                pollingHandler.isFirstComming = NO;
            }
            [PLProxyManager.sharedManager.pollingProxy pollingUnlockResultWithIsSuccess:YES];
            [PLXPCommandTool sendLoginUidIfNeeded];
            AudioServicesPlaySystemSoundWithCompletion(kSystemSoundID_Vibrate, ^{
                DLogTagInfo(kMultiBleOptTag, @"<PA>发送解锁指令成功，震动");
            });
        } failed:^(XPVehicleError * error) {
            [PLProxyManager.sharedManager.pollingProxy pollingUnlockResultWithIsSuccess:NO];
        }];
    }
}

