- (BOOL)pollingChargPortEnableIfNeed:(PLXPPollingHandler *)pollingHandler {
    if (self.pollingRunMode != PLPollingRunModeUnLock && self.pollingRunMode != PLPollingRunModeLockAndUnlock) {
        DLogTagInfo(kBLEKeyPollingTag, @"未开Polling解锁功能，返回,%d",self.pollingRunMode);
        return NO;
    }
    if ((XPChargePortState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"charge"][@"slow_charge_port_status"]) == XPChargePortStateOpen || (XPChargePortState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"charge"][@"fast_charge_port_status"]) == XPChargePortStateOpen) {
        DLogTagInfo(kBLEKeyPollingTag, @"充电口是Open状态，返回, %d, %d",  (XPChargePortState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"charge"][@"slow_charge_port_status"]),  (XPChargePortState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"charge"][@"fast_charge_port_status"]));
        return NO;
    }

    if ([self hasTwochargePort]) {
        if (((XPChargePortState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"charge"][@"slow_charge_port_status"]) == XPChargePortStateDefault || (XPChargePortState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"charge"][@"fast_charge_port_status"]) == XPChargePortStateDefault) && !self.isRemedy) {
            DLogTagInfo(kBLEKeyPollingTag, @"快慢充电口都是未知状态,不兜底，返回,%d",self.isRemedy);
            return NO;
        }
    }
    else
    {
        if ((XPChargePortState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"charge"][@"slow_charge_port_status"]) == XPChargePortStateDefault && !self.isRemedy) {
            DLogTagInfo(kBLEKeyPollingTag, @"充电口是未知状态,不兜底，返回,%d",self.isRemedy);
            return NO;
        }
    }

    return YES;
