    NSDate *currentTime = [NSDate date];
    if(self.prevDisableCommandTime && [[self.prevDisableCommandTime dateByAddingTimeInterval:pollingHandler.pollingUnlockDisableInterval] compare:currentTime] == NSOrderedDescending){
        DLogTagInfo(kBLEKeyPollingTag, @"<PA>想发disable，但是没有出上一次的disable间隔限制，返回");
        return NO;
    }

    return YES;
}

- (BOOL)pressUnlockIfNeed:(PLXPPollingSecondPollingHandler *)pollingHandler {
    if (self.pollingRunMode != PLPollingRunModeUnLock && self.pollingRunMode != PLPollingRunModeLockAndUnlock) {
        DLogTagInfo(kBLEKeyPollingTag, @"未开Polling解锁功能，返回,%d",self.pollingRunMode);
        return NO;
    }
    if ((XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]) ==XPVehicleDoorLockStateUnlocked) {
        DLogTagInfo(kBLEKeyPollingTag, @"车辆是解锁状态，返回,%d", (XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]));
        return NO;
    }
    if ((XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]) == XPVehicleDoorLockStateDefault) {
        DLogTagInfo(kBLEKeyPollingTag, @"手动解锁，车辆是解锁未知状态，返回,%d", (XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]));
        return NO;
    }

    if (self.pressUnlockTryCount >= 3) {
        DLogTagInfo(kBLEKeyPollingTag, @"<PA>想手动解锁，但超过三次，返回");
        return NO;
    }

    NSDate *currentTime = [NSDate date];
    if(self.prevHandUnlockCommnadTime && [[self.prevHandUnlockCommnadTime dateByAddingTimeInterval:pollingHandler.handUnlockInterval] compare:currentTime] == NSOrderedDescending){
        DLogTagInfo(kBLEKeyPollingTag, @"<PA>想解锁，但是没有出%d秒的解锁间隔限制，返回",pollingHandler.handUnlockInterval);
        return NO;
    }

    return YES;
}

- (BOOL)pressTrunkUnlockIfNeed:(PLXPPollingSecondPollingHandler *)pollingHandler {
    if (self.pollingRunMode != PLPollingRunModeUnLock && self.pollingRunMode != PLPollingRunModeLockAndUnlock) {
        DLogTagInfo(kBLEKeyPollingTag, @"未开Polling解锁功能，返回,%d",self.pollingRunMode);
        return NO;
    }
    if ((XPVehicleTrunkAjarState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"trunk_ajar_st"]) == XPVehicleTrunkAjarStateOpen) {
        DLogTagInfo(kBLEKeyPollingTag, @"后尾箱是解锁状态，返回,%d", (XPVehicleTrunkAjarState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"trunk_ajar_st"]));
        return NO;
    }
    if ((XPVehicleTrunkAjarState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"trunk_ajar_st"]) == XPVehicleTrunkAjarStateDefault) {
        DLogTagInfo(kBLEKeyPollingTag, @"后尾箱是解锁未知状态，返回,%d", (XPVehicleTrunkAjarState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"trunk_ajar_st"]));
        return NO;
    }
    if ((XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]) == XPVehicleDoorLockStateUnlocked && (XPKeyPowerMode)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"polling"][@"powerMode"]) == XPKeyPowerModeLocalON) {
        DLogTagInfo(kBLEConnectTag, @"解锁且本地On状态，不发送解锁后备箱");
        return NO;
    }
    if (self.pressUnlockTrunkCount >= 3) {
        DLogTagInfo(kBLEKeyPollingTag, @"pressUnlockTrunkCount重试超过三次");
        return NO;
    }

    NSDate *currentTime = [NSDate date];
    if(self.prevHandTrunkUnlockCommandTime && [[self.prevHandTrunkUnlockCommandTime dateByAddingTimeInterval:pollingHandler.handTrunkUnlockInterval] compare:currentTime] == NSOrderedDescending){
        DLogTagInfo(kBLEKeyPollingTag, @"<PA>想解锁后备箱，但是没有出%d秒的解锁间隔限制，返回",pollingHandler.handTrunkUnlockInterval);
        return NO;
    }

    return YES;
}

- (BOOL)pressSlowChargeOpenIfNeed:(PLXPPollingSecondPollingHandler *)pollingHandler {
    if (self.pollingRunMode != PLPollingRunModeUnLock && self.pollingRunMode != PLPollingRunModeLockAndUnlock) {
        DLogTagInfo(kBLEKeyPollingTag, @"未开Polling解锁功能，返回,%d",self.pollingRunMode);
        return NO;
    }
    if ((XPChargePortState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"charge"][@"slow_charge_port_status"]) == XPChargePortStateOpen) {
        DLogTagInfo(kBLEKeyPollingTag, @"充电口是开启状态，返回,%d", (XPChargePortState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"charge"][@"slow_charge_port_status"]));
        return NO;
    }
    if ((XPChargePortState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"charge"][@"slow_charge_port_status"]) == XPChargePortStateDefault) {
        DLogTagInfo(kBLEKeyPollingTag, @"充电口是未知状态，返回,%d", (XPChargePortState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"charge"][@"slow_charge_port_status"]));
        return NO;
    }
    if ((XPVehicleDoorLockState)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"door"][@"driver_door_lock_st"]) == XPVehicleDoorLockStateUnlocked && (XPKeyPowerMode)StateSafeEnum([PLVehicleStateInstance shareInstance].fullVehicleStateDict[@"polling"][@"powerMode"]) == XPKeyPowerModeLocalON) {
        DLogTagInfo(kBLEConnectTag, @"解锁且本地On状态，不发送解锁充电口");
        return NO;
    }
    NSDate *currentTime = [NSDate date];
    if(self.preHandSlowChargeOpenCommandTime && [[self.preHandSlowChargeOpenCommandTime dateByAddingTimeInterval:pollingHandler.handTrunkUnlockInterval] compare:currentTime] == NSOrderedDescending){
        DLogTagInfo(kBLEKeyPollingTag, @"<PA>想解锁充电口，但是没有出%d秒的解锁间隔限制，返回",pollingHandler.handTrunkUnlockInterval);
        return NO;
    }

    return YES;
}

- (BOOL)pressFastChargeOpenIfNeed:(PLXPPollingSecondPollingHandler *)pollingHandler {
    if (self.pollingRunMode != PLPollingRunModeUnLock && self.pollingRunMode != PLPollingRunModeLockAndUnlock) {
        DLogTagInfo(kBLEKeyPollingTag, @"未开Polling解锁功能，返回,%d",self.pollingRunMode);
