@interface PLXPBleLocationManager ()<PLXPBleRssiReceiveProtocol>

@property (nonatomic, strong) PLXPBleLocationHandler *bleLocationHandler;

@property (nonatomic, assign) BOOL isPaused;

@end

@implementation PLXPBleLocationManager

+ (PLXPBleLocationManager *)sharedManager {
    static id sharedMyModel = nil;
    static dispatch_once_t onceToken;

    dispatch_once(&onceToken, ^{
        sharedMyModel = [[self alloc] init];
    });

    return sharedMyModel;
}

- (instancetype)init {
    if (self = [super init]) {
        _parkingDistance = 4;
    }
    return self;
}

#pragma mark — XPBleLocationDataUpdateProtocol
// 更新定位1.0阈值
- (void)updateBleLocationV1Config:(NSArray *)configs {
    if ([self.bleLocationHandler isKindOfClass:[PLXPPollingFirstBleLocationHandler class]] && self.bleLocationHandler.locationVersion == PLBleLocationVersionV1) {
        if (self.bleLocationHandler.predictModel) {
            [self.bleLocationHandler.predictModel updateOTAPollingConfigs:configs];
        }
    }
}
// 更新定位2.0阈值
- (void)updateBleLocationV2Config:(NSArray *)configs {
    if ([self.bleLocationHandler isKindOfClass:[PLXPPollingOptBleLocationHandler class]] && self.bleLocationHandler.locationVersion == PLBleLocationVersionV2) {
        if (self.bleLocationHandler.predictModel) {
            [self.bleLocationHandler.predictModel updateOTAPollingConfigs:configs];
        }
    }
}

- (void)updateBleLocationV3Config:(NSArray *)configs {
    if ([self.bleLocationHandler isKindOfClass:[PLXPPollingKNNBleLocationHandler class]] && self.bleLocationHandler.locationVersion == PLBleLocationVersionV3) {
        if (self.bleLocationHandler.predictModel) {
            [self.bleLocationHandler.predictModel updateOTAPollingConfigs:configs];
        }
    }
}

// 更新海外定位泊车阈值
- (void)updateBleParkingLocationConfig:(NSArray *)configs {
    if ([self.bleLocationHandler isKindOfClass:[PLXPPollingKNNBleLocationHandler class]] && self.bleLocationHandler.locationVersion == PLBleLocationVersionV4) {
        if (self.bleLocationHandler.predictModel) {
            [self.bleLocationHandler.predictModel updateOTAPollingConfigs:configs];
        }
    }
}


#pragma mark — XPBleLocationLifeManageProtocol
- (void)initBleLocation:(PLBleLocationVersion)locationVersion bleHardWare:(NSString *)bleHardWare thresholdData:(NSArray *)thresholdData startDistance:(float)startDistance {
    DLogTagInfo(kMultiBleOptTag, @"<PA>初始化定位SDK");
    switch (locationVersion) {
        case PLBleLocationVersionV1:
        {
            PLXPPollingFirstBleLocationHandler *locationHandler = [[PLXPPollingFirstBleLocationHandler alloc]init];
            self.bleLocationHandler = locationHandler;
            [locationHandler setBleType:bleHardWare];
            [self.bleLocationHandler initBleLocationWithPredictConfig:[self makePredictConfig] otaConfig:thresholdData];
        }
            break;
        case PLBleLocationVersionV2:
        {
            PLXPPollingOptBleLocationHandler *handler = [[PLXPPollingOptBleLocationHandler alloc]init];
            self.bleLocationHandler = handler;
            [self.bleLocationHandler initBleLocationWithPredictConfig:[self makePredictConfig] otaConfig:thresholdData];
            [handler setStartDistance: startDistance];
        }
            break;
        case PLBleLocationVersionV3:
        {
            PLXPPollingKNNBleLocationHandler *handler = [[PLXPPollingKNNBleLocationHandler alloc]init];
            self.bleLocationHandler = handler;
            [self.bleLocationHandler initBleLocationWithPredictConfig:[self makePredictConfig] otaConfig:thresholdData];
            [handler setStartDistance: startDistance];
        }
            break;
        case PLBleLocationVersionV4:
        {
            PLXPPollingKNNBleLocationHandler *handler = [[PLXPPollingKNNBleLocationHandler alloc]init];
            self.bleLocationHandler = handler;
            [self.bleLocationHandler initBleLocationWithPredictConfig:[self makePredictConfig] otaConfig:thresholdData];
            [handler setStartDistance: startDistance];
        }
            break;

        default:
            break;
    }
    self.bleLocationHandler.locationVersion = locationVersion;
}

- (void)deinitBleLocation {
    DLogTagInfo(kMultiBleOptTag, @"释放predict资源");
    [self pauseBleLocation];
    [self.bleLocationHandler deInitBleLocation];
    self.bleLocationHandler = nil;
}

- (void)pauseBleLocation {
    self.isPaused = YES;
}

- (void)remuseBleLocation {
    self.isPaused = NO;
}

- (PLBLELocationResult)bleKeyIsInCar {
    if (self.isPaused) {
        DLogTagInfo(kBLEKeyPredictTag, @"paused, return");
        return PLBLELocationResultNone;
    }
    return [self.bleLocationHandler bleKeyIsInCar];
}

#pragma mark — XPBleConnectEventProtocol
- (void)bleDefinedConnected {
    [self.bleLocationHandler detectBleConnect:NO];
}

- (void)bleDefinedDisconnect {
}

- (void)bleRetryConnected {
    [self.bleLocationHandler detectBleConnect:YES];
}

- (void)bleSystemSwitch:(BOOL)isOn {
}

#pragma mark — XPBleCarEventProtocol
- (void)carLockIsLocked {
}

- (void)carDoorIsOpen {
}

- (void)carDoorIsClose {
}

#pragma mark plxpbleRssiReceiveProtocol
- (void)rssiManagerDidReceiveRssi:(PLXPRssiModel *)rssiModel {
    if (self.isPaused) {
        DLogTagInfo(kBLEKeyPredictTag, @"paused, return");
        return;
    }
    if ([self.bleLocationHandler isKindOfClass:[PLXPPollingFirstBleLocationHandler class]]) {
        PLXPPollingFirstBleLocationHandler *locationHandler = (PLXPPollingFirstBleLocationHandler *)self.bleLocationHandler;
        [locationHandler rssiManagerDidReceiveRssi:rssiModel];
    }
}

- (void)rssiManagerDidReceiveRssiArray:(NSArray<PLXPRssiModel *> *)rssiArray {
    if (self.isPaused) {
        DLogTagInfo(kBLEKeyPredictTag, @"paused, return");
        return;
    }
    if ([self.bleLocationHandler isKindOfClass:[PLXPPollingOptBleLocationHandler class]]) {
        PLXPPollingOptBleLocationHandler *locationHandler = (PLXPPollingOptBleLocationHandler *)self.bleLocationHandler;
        [locationHandler rssiManagerDidReceiveRssiArray:rssiArray];
    } else if ([self.bleLocationHandler isKindOfClass:[PLXPPollingKNNBleLocationHandler class]]) {
        PLXPPollingKNNBleLocationHandler *locationHandler = (PLXPPollingKNNBleLocationHandler *)self.bleLocationHandler;
        [locationHandler rssiManagerDidReceiveRssiArray:rssiArray];
    }
}


#pragma mark — setter && getter
- (void)setIsPaused:(BOOL)isPaused {
    _isPaused = isPaused;
    DLogTagInfo(kMultiBleOptTag, @"location pause state:%d",isPaused);
    [self.bleLocationHandler setIsPaused:isPaused];
}


- (PLPredictConfig *)makePredictConfig {
    PLPredictConfig * predictConfig = [PLPredictConfig new];
    predictConfig.mainStrongerRate = [PLVehicleConfigTool MAIN_STRONGER_RATE];
    predictConfig.slaveStrongerRate = [PLVehicleConfigTool SLAVE_STRONGER_RATE];
    predictConfig.defaultLockDistance = [PLVehicleConfigTool DEFAULT_LOCK_DISTANCE];
    predictConfig.defaultUnlockDistance = [PLVehicleConfigTool DEFAULT_UNLOCK_DISTANCE];
    predictConfig.defaultEnableDistance = [PLVehicleConfigTool DEFAULT_ENABLE_DISTANCE];
    return predictConfig;
}

@end

