@import XPVehicleSDK;
#endif  //XPPollingSDK_Test_Mode

@interface PLXPMultiBleLocationResultTool ()

@property (nonatomic, strong) NSMutableArray<id<PLXPBleLocationResultSyncProtocol>> *bleLocationResultManagers;

@end

@implementation PLXPMultiBleLocationResultTool

- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

- (void)addBleLocationResultManager:(id<PLXPBleLocationResultSyncProtocol>)eventManager {
    [self.bleLocationResultManagers addObject:eventManager];
}

- (void)removeBleLocationResultManager:(id<PLXPBleLocationResultSyncProtocol>)eventManager {
    [self.bleLocationResultManagers removeObject:eventManager];
}

- (void)startBleLocationResultObserver {
    @weakify(self);
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(predictSuccess:) name:kBleLocationPredictSuccess object:nil];
}

- (void)predictSuccess:(NSNotification *)x {
    NSDictionary *locationResult = x.userInfo;
    PLBLEKeyDistanceLevel distanceLevel = (PLBLEKeyDistanceLevel)[locationResult[@"distanceLevel"] intValue];
    for (id<PLXPBleLocationResultSyncProtocol> manager in self.bleLocationResultManagers) {
        if ([manager respondsToSelector:@selector(syncBleLocationResult:)]) {
            [manager syncBleLocationResult:locationResult];
        }
        if (distanceLevel >= PLBLEKeyDistanceLevelLockCircle) {
            [manager bleKeyIsFarAway];
            DLogTagInfo(kBLEKeyLocationTag, @"超过闭锁圈，重置手表闭锁");
            [[MMKV bl_mmkvWithVin:PLXPCTMediatorTool.vin userId:[@(PLXPCTMediatorTool.uid) stringValue] deviceModel:[PLXPUtility deviceModelName]] setBool:NO forKey:kWatchLock];
        }
    }
}

- (void)resetBleLocationResultObserver {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

#pragma mark — lazyload
- (NSMutableArray<id<PLXPBleLocationResultSyncProtocol>> *)bleLocationResultManagers {
    if (!_bleLocationResultManagers) {
        _bleLocationResultManagers = [NSMutableArray array];
    }
    return _bleLocationResultManagers;
}

@end

