190	    NSUInteger bleKeyPollingMode = [PLPollingEffectDataManager.sharedManager getKeySettingData].pollingRunMode;
191	    if(bleKeyPollingMode == 3) {
192	        DLogTagInfo(kBLEKeyPollingTag, @"MMKV读取Polling设置解闭锁,%@", keyWithVin);
193	        mmkvRunMode = PLPollingRunModeLockAndUnlock;
194	    } else if(bleKeyPollingMode == 1){
195	        DLogTagInfo(kBLEKeyPollingTag, @"MMKV读取Polling设置仅解锁,%@", keyWithVin);
196	        mmkvRunMode = PLPollingRunModeUnLock;
197	    } else if (bleKeyPollingMode == 2) {
198	        DLogTagInfo(kBLEKeyPollingTag, @"MMKV读取Polling设置仅闭锁,%@", keyWithVin);
199	        mmkvRunMode = PLPollingRunModeLock;
200	    } else{
201	        DLogTagInfo(kBLEKeyPollingTag, @"MMKV读取Polling设置关闭,%@", keyWithVin);
202	    }
203	    return mmkvRunMode;
204	}
