206	- (void)configPLPollingRunMode:(NSInteger)pollingRunMode {
207	    NSString *keyWithVin = [PLXPUtility appendVinToKey];
208	    //直接关闭
209	    if(pollingRunMode == PLPollingRunModeNone){
210	        DLogTagInfo(kBLEKeyPollingTag, @"Polling设置关闭,%@", keyWithVin);
211	        [self endPollingSDK];
212	    } else {
213	        switch (pollingRunMode) {
214	            case PLPollingRunModeUnLock:
215	                DLogTagInfo(kBLEKeyPollingTag, @"Polling设置仅解锁,%@", keyWithVin);
216	                break;
217	            case PLPollingRunModeLock:
218	                DLogTagInfo(kBLEKeyPollingTag, @"Polling设置为闭锁,%@", keyWithVin);
219	                break;
220	            case PLPollingRunModeLockAndUnlock:
221	                DLogTagInfo(kBLEKeyPollingTag, @"Polling设置解闭锁,%@", keyWithVin);
222	                break;
223	            default:
224	                break;
225	        }
226	        [self endPollingSDK];
227	        [self startPollingSDK];
228	        [self judgeBleLocationIsPaused];
229	    }
230	}
