433	- (void)vehicleStateChanged:(XPVehicleStateNotiObject *)object {
434	    if ((XPSleepMode)StateSafeEnum(object.diffVehicleDict[@"polling"][@"sleepModeState"]) != XPSleepModeDefault) {
435	        XPSleepMode sleepState = (XPSleepMode)StateSafeEnum(object.fullVehicleDict[@"polling"][@"sleepModeState"]);
436	        if (PLXPBLECarSleepModeStateActiveNotAvailable != sleepState) {
437	            self.isSleepMode = (PLXPBLECarSleepModeStateActive == sleepState);
438	            [self judgePollingIsPaused];
439	        }
440	    }
441	    if ((XPGearState)StateSafeEnum(object.diffVehicleDict[@"drive"][@"shift_state"]) != XPGearStateDefault) {
442	        PLXPBLEKeyCarGearValue gearValue = (PLXPBLEKeyCarGearValue)StateSafeEnum(object.fullVehicleDict[@"drive"][@"shift_state"]);
443	        if (gearValue == PLXPBLEKeyCarGearValueP || gearValue == PLXPBLEKeyCarGearValueInvaild) {
444	            DLogTagInfo(kBLEKeyPredictTag, @"车辆是P档，可以执行predict");
445	            self.gearValueIsSupportPolling = YES;
446	            self.gearValueIsSupportLocation = YES;
447	            [self judgeBleLocationIsPaused];
448	            [self judgePollingIsPaused];
449	        } else if (gearValue == PLXPBLEKeyCarGearValueN) {
450	            DLogTagInfo(kBLEKeyPredictTag, @"车辆是N档，可以执行predict,但不支持Polling");
451	            self.gearValueIsSupportPolling = NO;
452	            self.gearValueIsSupportLocation = YES;
453	            [self judgeBleLocationIsPaused];
454	            [self judgePollingIsPaused];
455	        } else {
456	            if (self.carStateIsRemedy && gearValue == PLXPBLEKeyCarGearValueNotAvailable) {
457	                self.gearValueIsSupportPolling = YES;
458	                self.gearValueIsSupportLocation = YES;
459	                [self judgeBleLocationIsPaused];
460	                [self judgePollingIsPaused];
461	            } else {
462	                DLogTagInfo(kBLEKeyPredictTag, @"车辆不是P档或N档，同时不执行predict与Polling");
463	                self.gearValueIsSupportPolling = NO;
464	                self.gearValueIsSupportLocation = NO;
465	                [self judgePollingIsPaused];
466	                [self judgeBleLocationIsPaused];
467	            }
468	        }
469	    }
