588	- (void)observeValueForKeyPath:(NSString *)keyPath ofObject:(id)object change:(NSDictionary<NSKeyValueChangeKey,id> *)change context:(void *)context {
589	    if ([@"bleHardWare" isEqualToString:keyPath] && object == PLXPBLEInfoManager.manager) {
590	        NSString *x = PLXPBLEInfoManager.manager.bleHardWare;
591	        DLogTagInfo(kPollingSelfDefinedTag, @"监测到整车BLE版本变化:%@",x);
