598	- (void)configBleInfo:(NSString *)x{
599	    if (x && [x length] > 0){
600	        if ([PLXPUtility isEmptyWithString:x]) {
601	            self.currentBleHardWare = x;
602	            [self endPollingSDK];
603	            [self endBleLocationSDK];
604	            [self startBleLocationSDK];
605	            [self startPollingSDK];
606	        } else {
607	            if (![self.currentBleHardWare isEqualToString:x]) {
608	                self.currentBleHardWare = x;
609	                [self endPollingSDK];
610	                [self endBleLocationSDK];
611	                [self startBleLocationSDK];
612	                [self startPollingSDK];
613	            }
614	        }
615	    } else {
616	        self.currentBleHardWare = nil;
617	        [self endPollingSDK];
618	        [self endBleLocationSDK];
619	    }
620	    DLogTagInfo(kBLEKeyPollingTag, @"currentBleHardWare %@", self.currentBleHardWare);
621	}
