#define PLRefreshSystemConfigSuccessNotificaiton  @"RefreshSystemConfigSuccessNotificaiton"

typedef NS_ENUM(unsigned short,PLXPAppAutoParkingState) {
    PLXPAppAutoParkingStateChecking = 0,
    PLXPAppAutoParkingStateParkReady,
    PLXPAppAutoParkingStateParkPause,
    PLXPAppAutoParkingStateParking,
    PLXPAppAutoParkingStateParkComplete,
    PLXPAppAutoParkingStateQuit,
    PLXPAppAutoParkingStateParkInAvariable,
    PLXPAppAutoParkingStateParkOutAvariable,
    PLXPAppAutoParkingStateSummoning,
    PLXPAppAutoParkingStateSummoningAvariable,
    PLXPAppAutoParkingStatePhysicalKeyParking,
    PLXPAppAutoParkingStateNotAvariable=0xF
};

typedef NS_ENUM(uint8_t,PLXPBLECarSleepModeState) {
    PLXPBLECarSleepModeStateNotActive = 0,
    PLXPBLECarSleepModeStateActive,
    PLXPBLECarSleepModeStateActiveNotAvailable = 0xFF
};

typedef NS_ENUM(uint8_t,PLXPBLEKeyCarGearValue) {
    PLXPBLEKeyCarGearValueInvaild = 0,
    PLXPBLEKeyCarGearValueD = 1,
    PLXPBLEKeyCarGearValueN = 2,
    PLXPBLEKeyCarGearValueR = 3,
    PLXPBLEKeyCarGearValueP = 4,
    PLXPBLEKeyCarGearValueNotAvailable = 0xFF,
};


@interface PLXPMultiBleManager () <PLVehicleStateInstanceProtocol>

@property (nonatomic, copy) NSString *currentVin;
@property (nonatomic, copy) NSString *currentBleHardWare;
@property (nonatomic, assign) BOOL currentCarIsPollingStart;
@property (nonatomic, assign) BOOL currentCarIsBleLocationStart;

@property (nonatomic, assign) BOOL isPollingCalibration;
@property (nonatomic, assign) BOOL isInParkingController;
@property (nonatomic, assign) BOOL isInParkingProcess;
@property (nonatomic, assign) BOOL isAutoParking;
@property (nonatomic, assign) BOOL isSleepMode;
@property (nonatomic, assign) BOOL gearValueIsSupportLocation;
@property (nonatomic, assign) BOOL gearValueIsSupportPolling;

@property (nonatomic, assign) BOOL mobileParkingNeedLocation;
@property (nonatomic, assign) BOOL pollingAndLocationIsBind;
@property (nonatomic, assign) BOOL drivingNeedLocation;
@property (nonatomic, weak) id<PLXPBleLocationLifeManageProtocol> bleLocationLifeManager;
@property (nonatomic, weak) id<PLXPBlePollingLifeManageProtocol> blePollingLifeManager;

@property (nonatomic, strong) PLXPMultiBleEventTool *bleEventTool;
@property (nonatomic, strong) PLXPMultiBleLocationResultTool *bleLocationTool;

@end

@implementation PLXPMultiBleManager

+ (PLXPMultiBleManager *)sharedManager {
    static id sharedManager = nil;
#if !defined(MONA_APP)
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        sharedManager = [[self alloc] init];
    });
#endif  //XPPollingSDK_Test_Mode
    return sharedManager;
}

- (instancetype)init {
    if (self = [super init]) {
        _bleEventTool = [[PLXPMultiBleEventTool alloc]init];
        _bleLocationTool = [[PLXPMultiBleLocationResultTool alloc]init];
    }
    return self;
}

- (void)start {
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        @weakify(self);
        [[[[NSNotificationCenter defaultCenter] rac_addObserverForName:PLLogInOutNotification object:nil] takeUntil:self.rac_willDeallocSignal] subscribeNext:^(NSNotification * _Nullable x) {
            @strongify(self);
            if (PLXPCTMediatorTool.uid <=0) {
                [self switchDiffCar:nil];
            } else {
                [self switchDiffCar:self.currentVin];
            }
        }];

    });
}

- (void)vehicleInfoUpdate{
    NSString *vin = PLXPCTMediatorTool.vin;
    if (!self.pluginSwitchDisable && [PLXPCTMediatorTool isLogin]) {
        if ([PLXPUtility isEmptyWithString:vin]) {
            [self switchDiffCar:vin];
        } else {
            if ([PLVehicleConfigTool isBleKeyProtocolVesionV2] || [PLVehicleConfigTool isBleKeyProtocolVesionV1]) {
                if (!self.currentVin) {
                    DLogTagInfo(kBLEKeyPollingTag, @"<PA> 第一次获取vin，初始化polling与定位资源");
                    [self switchDiffCar:vin];
                } else {
                    if (![self.currentVin isEqualToString:vin]) {
                        DLogTagInfo(kBLEKeyPollingTag, @"<PA> vin不相同，重新初始化polling与定位资源");
                        [self switchDiffCar:vin];
                    } else {
                        DLogTagInfo(kBLEKeyPollingTag, @"<PA> vin相同，不初始化polling资源");
                    }
                }
            } else {
                [self switchDiffCar:nil];
            }
        }
    } else {
        [self switchDiffCar:nil];
    }
}

#pragma mark - Permission
+ (BOOL)checkIfPermissionGranted{
    return [self checkIfLocationPermissionGranted] && [self checkIfAccuracyLocationPermissionGranted] && [self checkIfBackgroundPermissionGranted];
}

+ (BOOL)checkIfLocationPermissionGranted{
    if([[PLPermissionManager sharedInstance] authorizationStatus:PLPrivacyPermissionTypeLocation] != PLPrivacyPermissionAuthorizationStatusLocationAlways) {
        return NO;
    }
    return YES;
}

+ (BOOL)checkIfAccuracyLocationPermissionGranted{
    if([[PLPermissionManager sharedInstance] authorizationStatus:PLPrivacyPermissionTypeAccuracy] != PLPrivacyPermissionAuthorizationStatusAuthorized) {
        return NO;
    }
    return YES;
}

+ (BOOL)checkIfBackgroundPermissionGranted{
    PLPrivacyPermissionAuthorizationStatus backgroundAuthorizationStatus = [[PLPermissionManager sharedInstance] authorizationStatus:PLPrivacyPermissionTypeBackgroundRefresh];
    if(backgroundAuthorizationStatus == PLPrivacyPermissionAuthorizationStatusDenied){
        return NO;
    }
    return YES;
}

#pragma mark — PLPollingRunModeSetting
- (PLPollingRunMode)getPollingSettingFromMMKV{
    PLPollingRunMode mmkvRunMode = PLPollingRunModeNone;
    NSString *keyWithVin = [PLXPUtility appendVinToKey];

    NSUInteger bleKeyPollingMode = [PLPollingEffectDataManager.sharedManager getKeySettingData].pollingRunMode;
    if(bleKeyPollingMode == 3) {
        DLogTagInfo(kBLEKeyPollingTag, @"MMKV读取Polling设置解闭锁,%@", keyWithVin);
        mmkvRunMode = PLPollingRunModeLockAndUnlock;
    } else if(bleKeyPollingMode == 1){
        DLogTagInfo(kBLEKeyPollingTag, @"MMKV读取Polling设置仅解锁,%@", keyWithVin);
        mmkvRunMode = PLPollingRunModeUnLock;
    } else if (bleKeyPollingMode == 2) {
        DLogTagInfo(kBLEKeyPollingTag, @"MMKV读取Polling设置仅闭锁,%@", keyWithVin);
        mmkvRunMode = PLPollingRunModeLock;
    } else{
        DLogTagInfo(kBLEKeyPollingTag, @"MMKV读取Polling设置关闭,%@", keyWithVin);
    }
    return mmkvRunMode;
}

- (void)configPLPollingRunMode:(NSInteger)pollingRunMode {
    NSString *keyWithVin = [PLXPUtility appendVinToKey];
    //直接关闭
    if(pollingRunMode == PLPollingRunModeNone){
        DLogTagInfo(kBLEKeyPollingTag, @"Polling设置关闭,%@", keyWithVin);
        [self endPollingSDK];
    } else {
        switch (pollingRunMode) {
            case PLPollingRunModeUnLock:
                DLogTagInfo(kBLEKeyPollingTag, @"Polling设置仅解锁,%@", keyWithVin);
                break;
            case PLPollingRunModeLock:
                DLogTagInfo(kBLEKeyPollingTag, @"Polling设置为闭锁,%@", keyWithVin);
                break;
            case PLPollingRunModeLockAndUnlock:
                DLogTagInfo(kBLEKeyPollingTag, @"Polling设置解闭锁,%@", keyWithVin);
                break;
            default:
                break;
        }
        [self endPollingSDK];
        [self startPollingSDK];
        [self judgeBleLocationIsPaused];
    }
}

#pragma mark — private
- (void)reset {
    self.isPollingCalibration = NO;
    self.isInParkingController = NO;
    self.isAutoParking = NO;
    self.isInParkingProcess = NO;
    self.isSleepMode = NO;
    self.gearValueIsSupportPolling = YES;
    self.gearValueIsSupportLocation = YES;
    self.carStateIsRemedy = YES;
    [[NSNotificationCenter defaultCenter] removeObserver:self];
    [[PLVehicleStateInstance shareInstance] removeListener:self];
    [self.bleEventTool resetBleEventObserver];
    [self.bleLocationTool resetBleLocationResultObserver];
    @try {
        [PLXPBLEInfoManager.manager removeObserver:self forKeyPath:@"bleHardWare" context:nil];
    }
    @catch (NSException *exception) {
        NSLog(@"KVO移除异常：%@", exception);
    }
}

- (void)startPollingSDK {
    DLogTagInfo(kMultiBleOptTag, @"即将启动PollingSDK");
    if (self.currentCarIsPollingStart) {
        DLogTagInfo(kMultiBleOptTag, @"<PA>已经初始化过pollingSDK");
        return;
    }
    if ([PLPollingEffectDataManager.sharedManager getKeySettingData].pollingRunMode == PLPollingRunModeNone) {
        DLogTagInfo(kMultiBleOptTag, @"<PA>[PLXPPollingSettingTool pollingMode] == PLPollingRunModeNone，返回");
        return;
    }
    if(![PLXPCTMediatorTool isBleKeyAvailable]) {
        DLogTagInfo(kMultiBleOptTag, @"<PA>用户不存在钥匙，初始化polling失败，返回");
        return;
    }

#ifndef XPPollingSDK_Test_Mode
    XPBLEInfo *bleInfo = [XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager validBlePrivateKey].bleInfo;
    NSString *mainBleMacAddress = bleInfo.macAddress;
    if(mainBleMacAddress.length <= 0) {
        DLogTagInfo(kMultiBleOptTag, @"<PA>主蓝牙为空，初始化polling失败，返回");
        return;
    }

    if([PLVehicleConfigTool isBleLocationVersionNotSupport] && [PLVehicleConfigTool isParkLocationVersionNotSupport]) {
        DLogTagInfo(kMultiBleOptTag, @"<PA>不是多蓝牙车型，没有定位功能");
        return;
    }
#endif  //XPPollingSDK_Test_Mode

    self.blePollingLifeManager = [PLXPPollingManager sharedManager];
    PLPollingEffectDataManager.sharedManager.blePollingUpdateDataManager = [PLXPPollingManager sharedManager];
    [self.bleEventTool addBleCarEventManager:[PLXPPollingManager sharedManager]];
    [self.bleEventTool addBleConnectEventManager:[PLXPPollingManager sharedManager]];
    [self.bleLocationTool addBleLocationResultManager:[PLXPPollingManager sharedManager]];
    if ([self.blePollingLifeManager respondsToSelector:@selector(initBlePollingWithKeySettingData:isRemedy:)]) {
        [self.blePollingLifeManager initBlePollingWithKeySettingData: PLPollingEffectDataManager.sharedManager.getKeySettingData isRemedy:self.carStateIsRemedy];
    }
    [self.bleEventTool syncCachedEvent];
    [self judgePollingIsPaused];
    self.currentCarIsPollingStart = YES;
}

- (void)endPollingSDK {
    DLogTagInfo(kMultiBleOptTag, @"结束PollingSDK");
    if (self.currentCarIsPollingStart) {
        if ([self.blePollingLifeManager respondsToSelector:@selector(deinitBlePolling)]) {
            [self.blePollingLifeManager deinitBlePolling];
        }
        self.blePollingLifeManager = nil;
        PLPollingEffectDataManager.sharedManager.blePollingUpdateDataManager = nil;
        [self.bleEventTool removeCarBleEventManager:[PLXPPollingManager sharedManager]];
        [self.bleEventTool removeBleConnectEventManager:[PLXPPollingManager sharedManager]];
        [self.bleLocationTool removeBleLocationResultManager:[PLXPPollingManager sharedManager]];
        self.currentCarIsPollingStart = NO;
    }
}

- (void)startBleLocationSDK {
    DLogTagInfo(kMultiBleOptTag, @"即将启动定位SDK");
    if (self.currentCarIsBleLocationStart) {
        DLogTagInfo(kMultiBleOptTag, @"<PA>已经初始化过定位SDK");
        return;
    }
    if(![PLXPCTMediatorTool isBleKeyAvailable]) {
        DLogTagInfo(kMultiBleOptTag, @"<PA>用户不存在钥匙，初始化定位SDK失败，返回");
        return;
    }

#ifndef XPPollingSDK_Test_Mode
    XPBLEInfo *bleInfo = [XPVehicleSDK.shared.vehicleManager.currentVehicle.digitalKeyManager validBlePrivateKey].bleInfo;
    NSString *mainBleMacAddress = bleInfo.macAddress;
    if(!bleInfo.macAddress || [bleInfo.macAddress isEqualToString:@""]) {
        DLogTagInfo(kMultiBleOptTag, @"<PA>主蓝牙为空，初始化定位SDK失败，返回");
        return;
    }
#endif  //XPPollingSDK_Test_Mode

    if([PLVehicleConfigTool isBleLocationVersionNotSupport] && [PLVehicleConfigTool isParkLocationVersionNotSupport]) {
        DLogTagInfo(kMultiBleOptTag, @"<PA>不是多蓝牙车型，没有定位功能");
        return;
    }
    if (self.currentBleHardWare.length <= 0) {
        DLogTagInfo(kMultiBleOptTag, @"<PA>多蓝牙硬件版本号位空，返回");
        return;
    }

    self.bleLocationLifeManager = [PLXPBleLocationManager sharedManager];
    PLPollingEffectDataManager.sharedManager.bleLocationUpdateDataManager = [PLXPBleLocationManager sharedManager];
    [self.bleEventTool addBleCarEventManager:[PLXPBleLocationManager sharedManager]];
    [self.bleEventTool addBleConnectEventManager:[PLXPBleLocationManager sharedManager]];
    [self.bleEventTool addBleRssiReceiveManager:[PLXPBleLocationManager sharedManager]];
    if ([self.bleLocationLifeManager respondsToSelector:@selector(initBleLocation:bleHardWare:thresholdData:startDistance:)]) {
        if (self.isInParkingController && self.mobileParkingNeedLocation) {
            [self.bleLocationLifeManager initBleLocation:[PLVehicleConfigTool PARKING_LOCATION_VERSION]
                                             bleHardWare:self.currentBleHardWare
                                           thresholdData:[[PLPollingEffectDataManager sharedManager] getPollingThreshold:[PLVehicleConfigTool PARKING_LOCATION_VERSION]]
                                           startDistance:[PLPollingEffectDataManager.sharedManager getKeySettingData].startDistance];
        } else {
            [self.bleLocationLifeManager initBleLocation:(PLBleLocationVersion)[PLVehicleConfigTool bleLocationVersion]
                                             bleHardWare:self.currentBleHardWare
                                           thresholdData:[[PLPollingEffectDataManager sharedManager] getPollingThreshold:(PLBleLocationVersion)[PLVehicleConfigTool bleLocationVersion]]
                                           startDistance:[PLPollingEffectDataManager.sharedManager getKeySettingData].startDistance];
        }
    }
    [self judgeBleLocationIsPaused];
    self.currentCarIsBleLocationStart = YES;
}

- (void)endBleLocationSDK {
    DLogTagInfo(kMultiBleOptTag, @"结束定位SDK");
    if (self.currentCarIsBleLocationStart) {
        if ([self.bleLocationLifeManager respondsToSelector:@selector(deinitBleLocation)]) {
            [self.bleLocationLifeManager deinitBleLocation];
        }
        self.bleLocationLifeManager = nil;
        PLPollingEffectDataManager.sharedManager.bleLocationUpdateDataManager = nil;
        [self.bleEventTool removeCarBleEventManager:[PLXPBleLocationManager sharedManager]];
        [self.bleEventTool removeBleConnectEventManager:[PLXPBleLocationManager sharedManager]];
        [self.bleEventTool removeBleRssiReceiveManager:[PLXPBleLocationManager sharedManager]];
        self.currentCarIsBleLocationStart = NO;
    }
}

- (void)addObserver {
#if 0
    self.bleAddressUpdateDisposable = [[[[NSNotificationCenter defaultCenter] rac_addObserverForName:XP_BLE_ADDRESS_UPDATE_COMPLETE object:nil] takeUntil:self.rac_willDeallocSignal] subscribeNext:^(NSNotification * _Nullable x) {
        @strongify(self);
        [self startBleLocationSDK];
        [self startPollingSDK];
    }];

    self.deleteBleKeySuccessDisposable = [[[[NSNotificationCenter defaultCenter] rac_addObserverForName:XPDeletingBleKeyNotification object:nil] takeUntil:self.rac_willDeallocSignal] subscribeNext:^(NSNotification * _Nullable x) {
        @strongify(self);
        [self endPollingSDK];
        [self endBleLocationSDK];
    }];

    self.createBleKeySuccessDisposable = [[[[NSNotificationCenter defaultCenter] rac_addObserverForName:XPCreatingBleKeyNotification object:nil] takeUntil:self.rac_willDeallocSignal] subscribeNext:^(NSNotification * _Nullable x) {
        @strongify(self);
        [self startBleLocationSDK];
        [self startPollingSDK];
    }];

#endif


    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(digitalKeyStateChanged:) name:XPVehicleNotification.DigitalKeyStateChanged object:nil];

    [PLXPBLEInfoManager.manager addObserver:self forKeyPath:@"bleHardWare" options:NSKeyValueObservingOptionNew|NSKeyValueObservingOptionOld context:nil];

    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(pollingIsCalibration:) name:kNotificationNamePollingIsCalibration object:nil];

    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(mobileParkingNoti:) name:PLXPMobileParkingNotification object:nil];

    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(refreshSystemConfigSuccess:) name:PLRefreshSystemConfigSuccessNotificaiton object:nil];

    @weakify(self)
    [[XPVehicleSDK.shared.vehicleManager.currentVehicle.autoDriveManager.bleParking.parkStateInfoChangedEvent on:^(id _Nonnull data) {
        if (![data isKindOfClass:[XPBleParkInfo class]]) {
            return;
        }
        @strongify(self)
        XPBleParkInfo *bleParkInfo = data;
        [self parkingStateChanged: (PLXPAppAutoParkingState)bleParkInfo.parkState];
    }] bind:self];

    [[PLVehicleStateInstance shareInstance] addListener:self];

    [self.bleEventTool startBleEventObserver];
    [self.bleLocationTool startBleLocationResultObserver];

#ifndef XPPollingSDK_Test_Mode
    [self configBleInfo:PLXPBLEInfoManager.manager.bleHardWare];
#endif  //XPPollingSDK_Test_Mode

}

#pragma mark — NSNotification Action

- (void)vehicleStateChanged:(XPVehicleStateNotiObject *)object {
    if ((XPSleepMode)StateSafeEnum(object.diffVehicleDict[@"polling"][@"sleepModeState"]) != XPSleepModeDefault) {
        XPSleepMode sleepState = (XPSleepMode)StateSafeEnum(object.fullVehicleDict[@"polling"][@"sleepModeState"]);
        if (PLXPBLECarSleepModeStateActiveNotAvailable != sleepState) {
            self.isSleepMode = (PLXPBLECarSleepModeStateActive == sleepState);
            [self judgePollingIsPaused];
        }
    }
    if ((XPGearState)StateSafeEnum(object.diffVehicleDict[@"drive"][@"shift_state"]) != XPGearStateDefault) {
        PLXPBLEKeyCarGearValue gearValue = (PLXPBLEKeyCarGearValue)StateSafeEnum(object.fullVehicleDict[@"drive"][@"shift_state"]);
        if (gearValue == PLXPBLEKeyCarGearValueP || gearValue == PLXPBLEKeyCarGearValueInvaild) {
            DLogTagInfo(kBLEKeyPredictTag, @"车辆是P档，可以执行predict");
            self.gearValueIsSupportPolling = YES;
            self.gearValueIsSupportLocation = YES;
            [self judgeBleLocationIsPaused];
            [self judgePollingIsPaused];
        } else if (gearValue == PLXPBLEKeyCarGearValueN) {
            DLogTagInfo(kBLEKeyPredictTag, @"车辆是N档，可以执行predict,但不支持Polling");
            self.gearValueIsSupportPolling = NO;
            self.gearValueIsSupportLocation = YES;
            [self judgeBleLocationIsPaused];
            [self judgePollingIsPaused];
        } else {
            if (self.carStateIsRemedy && gearValue == PLXPBLEKeyCarGearValueNotAvailable) {
                self.gearValueIsSupportPolling = YES;
                self.gearValueIsSupportLocation = YES;
                [self judgeBleLocationIsPaused];
                [self judgePollingIsPaused];
            } else {
                DLogTagInfo(kBLEKeyPredictTag, @"车辆不是P档或N档，同时不执行predict与Polling");
                self.gearValueIsSupportPolling = NO;
                self.gearValueIsSupportLocation = NO;
                [self judgePollingIsPaused];
                [self judgeBleLocationIsPaused];
            }
        }
    }
}

- (void)digitalKeyStateChanged:(NSNotification *)noti {
    if ([PLXPCTMediatorTool isBleKeyAvailable]) {
        [self startBleLocationSDK];
        [self startPollingSDK];
    } else {
        [self endBleLocationSDK];
        [self endPollingSDK];
    }
}

- (void)pollingIsCalibration:(NSNotification *)noti {
    BOOL isCalibration = [noti.object boolValue];
    DLogTagInfo(kMultiBleOptTag, @"Polling是否校准中:%d",isCalibration);
    self.isPollingCalibration = isCalibration;
    [self judgePollingIsPaused];
    [self judgeBleLocationIsPaused];
}

- (void)mobileParkingNoti:(NSNotification *)noti {
    int parkingValue = [noti.object intValue];
    if (parkingValue == 0) {
        self.isInParkingController = NO;
        self.isInParkingProcess = NO;
    } else if (parkingValue == 1) {
        self.isInParkingController = YES;
        self.isInParkingProcess = YES;
    } else {
        self.isInParkingProcess = NO;
    }
    [self judgePollingIsPaused];
    [self judgeBleLocationIsPaused];
    if (self.mobileParkingNeedLocation) {
        [self resetLocationParking];
    }
}

- (void)refreshSystemConfigSuccess:(NSNotification *)noti {
    [self configBLEInfo];
}

- (void)parkingStateChanged:(PLXPAppAutoParkingState)parkingState {
    if (parkingState != PLXPAppAutoParkingStateQuit && parkingState != PLXPAppAutoParkingStateChecking && parkingState != PLXPAppAutoParkingStateNotAvariable) {
        DLogTagInfo(kBLEKeyPredictTag, @"车辆正在自动泊车，不执行polling");
        self.isAutoParking = YES;
        [self judgePollingIsPaused];
        [self judgeBleLocationIsPaused];
    } else {
        self.isAutoParking = NO;
        [self judgeBleLocationIsPaused];
        [self judgePollingIsPaused];
    }
}

#pragma mark --private
- (void)switchDiffCar:(NSString *)vin {
    [self reset];
    [self endPollingSDK];
    [self endBleLocationSDK];
    [[PLXPBLEInfoManager manager] end];
    self.currentVin = vin;
    if (![PLXPUtility isEmptyWithString:vin]) {
        [PLPollingEffectDataManager.sharedManager updateKeySettingData:vin];
        [self addObserver];
        self.carStateIsRemedy = PLPollingEffectDataManager.sharedManager.getKeySettingData.carStateIsRemedy;
        [self configBLEInfo];
        [self startBleLocationSDK];
        [self startPollingSDK];
    }
}

- (void)configBLEInfo {
#ifdef XPPollingSDK_Test_Mode
    NSDictionary * bleHardInfoMap = [[PLPolllingTestMockSetting getOTABleHardMap]valueForKey:PLPolllingTestMockSetting.vehicleTypeName ? : @""];
#else
    NSDictionary * bleHardInfoMap = [[PLPollingEffectDataManager.sharedManager getKeySettingData].bleHardMap valueForKey:PLXPCTMediatorTool.vehicleTypeName];
#endif //XPPollingSDK_Test_Mode
    [[PLXPBLEInfoManager manager] start:bleHardInfoMap];
}

- (void)judgePollingIsPaused {
    if (self.isPollingCalibration || self.isInParkingProcess || self.isAutoParking || !self.gearValueIsSupportPolling || self.isSleepMode) {
        DLogTagInfo(kMultiBleOptTag, @"polling服务要暂停:isPollingCalibration:%d,isInParkingProcess:%d,isAutoParking:%d,gearValueIsSupportPolling:%d,isSleepMode:%d",self.isPollingCalibration,self.isInParkingProcess,self.isAutoParking,self.gearValueIsSupportPolling,self.isSleepMode);
        if ([self.blePollingLifeManager respondsToSelector:@selector(pauseBlePolling)]) {
            [self.blePollingLifeManager pauseBlePolling];
        }
        return;
    }
    DLogTagInfo(kMultiBleOptTag, @"polling服务要恢复");
    if ([self.blePollingLifeManager respondsToSelector:@selector(remuseBlePolling)]) {
        [self.blePollingLifeManager remuseBlePolling];
    }
}

- (void)judgeBleLocationIsPaused {
    if ([PLPollingEffectDataManager.sharedManager getKeySettingData].pollingRunMode == PLPollingRunModeNone && self.pollingAndLocationIsBind) {
        DLogTagInfo(kMultiBleOptTag, @"predict服务要暂停,PLPollingRunMode:%d,pollingAndLocationIsBind:%d", [PLPollingEffectDataManager.sharedManager getKeySettingData].pollingRunMode, self.pollingAndLocationIsBind);
        if ([self.bleLocationLifeManager respondsToSelector:@selector(pauseBleLocation)]) {
            [self.bleLocationLifeManager pauseBleLocation];
        }
        return;
    }
    if (!self.gearValueIsSupportLocation) {
        if (!self.drivingNeedLocation && !self.isInParkingController && !self.isPollingCalibration) {
            DLogTagInfo(kMultiBleOptTag, @"predict服务要暂停,gearValueIsSupportLocation:%d",self.gearValueIsSupportLocation);
            if ([self.bleLocationLifeManager respondsToSelector:@selector(pauseBleLocation)]) {
                [self.bleLocationLifeManager pauseBleLocation];
            }
            return;
        }
    }
    DLogTagInfo(kMultiBleOptTag, @"predict服务要恢复");
    if ([self.bleLocationLifeManager respondsToSelector:@selector(remuseBleLocation)]) {
        [self.bleLocationLifeManager remuseBleLocation];
    }
}

- (void)observeValueForKeyPath:(NSString *)keyPath ofObject:(id)object change:(NSDictionary<NSKeyValueChangeKey,id> *)change context:(void *)context {
    if ([@"bleHardWare" isEqualToString:keyPath] && object == PLXPBLEInfoManager.manager) {
        NSString *x = PLXPBLEInfoManager.manager.bleHardWare;
        DLogTagInfo(kPollingSelfDefinedTag, @"监测到整车BLE版本变化:%@",x);
        [self configBleInfo:x];
    } else {
        [super observeValueForKeyPath:keyPath ofObject:object change:change context:context];
    }
}

- (void)configBleInfo:(NSString *)x{
    if (x && [x length] > 0){
        if ([PLXPUtility isEmptyWithString:x]) {
            self.currentBleHardWare = x;
            [self endPollingSDK];
            [self endBleLocationSDK];
            [self startBleLocationSDK];
            [self startPollingSDK];
        } else {
            if (![self.currentBleHardWare isEqualToString:x]) {
                self.currentBleHardWare = x;
                [self endPollingSDK];
                [self endBleLocationSDK];
                [self startBleLocationSDK];
                [self startPollingSDK];
            }
        }
    } else {
        self.currentBleHardWare = nil;
        [self endPollingSDK];
        [self endBleLocationSDK];
    }
    DLogTagInfo(kBLEKeyPollingTag, @"currentBleHardWare %@", self.currentBleHardWare);
}

- (void)resetLocationParking {
    [self endBleLocationSDK];
    [self startBleLocationSDK];
}

#pragma mark — lazyload
- (void)setCarStateIsRemedy:(BOOL)carStateIsRemedy {
    _carStateIsRemedy = carStateIsRemedy;
}

- (BOOL)mobileParkingNeedLocation {
#ifndef XPPollingSDK_Test_Mode
    if ([XPCarLocalConfig boolForKey:@"mobileParkingNeedLocation"]) {
        return YES;
    } else {
        return NO;
    }
#else
    return YES;
#endif  //XPPollingSDK_Test_Mode
}

- (BOOL)pollingAndLocationIsBind {
    return [PLVehicleConfigTool POLLING_AND_LOCATION_IS_BIND];
}

- (BOOL)drivingNeedLocation {
    return [PLVehicleConfigTool DRIVING_NEED_LOCATION];
}

@end

